@app.route("/api/departments")
@api_login_required
def api_departments():
    with get_db() as c:
        rows = c.execute("SELECT * FROM departments ORDER BY name").fetchall()
    return jsonify([dict(r) for r in rows])

@app.route("/api/positions")
@api_login_required
def api_positions():
    with get_db() as c:
        rows = c.execute("""
            SELECT p.*, d.name dept_name, d.code dept_code
            FROM positions p LEFT JOIN departments d ON d.id=p.department_id
            WHERE p.is_active=1 ORDER BY p.category, p.title""").fetchall()
    return jsonify([dict(r) for r in rows])

@app.route("/api/positions", methods=["POST"])
@api_login_required
def api_create_position():
    d = request.json
    if not all(d.get(k) for k in ("title","category","employment_type")):
        return jsonify({"error":"Missing required fields"}), 400
    with get_db() as c:
        cur = c.execute(
            "INSERT INTO positions (title,department_id,category,employment_type,slots_available) VALUES (?,?,?,?,?)",
            (d["title"],d.get("department_id"),d["category"],d["employment_type"],d.get("slots_available",1)))
    return jsonify({"id":cur.lastrowid,"message":"Position created"}), 201

@app.route("/api/positions/<int:pid>", methods=["DELETE"])
@api_login_required
def api_delete_position(pid):
    with get_db() as c:
        c.execute("UPDATE positions SET is_active=0 WHERE id=?", (pid,))
    return jsonify({"message":"Position removed"})

@app.route("/api/positions/<int:pid>", methods=["PUT"])
@api_login_required
def api_update_position(pid):
    d = request.json
    if not all(d.get(k) for k in ("title","category","employment_type")):
        return jsonify({"error":"Missing required fields"}), 400
    with get_db() as c:
        c.execute("""UPDATE positions SET title=?,department_id=?,category=?,
                     employment_type=?,slots_available=? WHERE id=?""",
                  (d["title"],d.get("department_id"),d["category"],
                   d["employment_type"],d.get("slots_available",1),pid))
    return jsonify({"message":"Position updated"})

@app.route("/api/personnel")
@api_login_required
def api_personnel():
    dept   = request.args.get("department_id","")
    cat    = request.args.get("category","")
    active = request.args.get("active","1")
    q = """
        SELECT pe.*, p.title position_title, p.category,
               d.name dept_name, d.code dept_code
        FROM personnel pe
        JOIN positions   p ON p.id=pe.position_id
        LEFT JOIN departments d ON d.id=pe.department_id
        WHERE 1=1"""
    params=[]
    if active != "":
        q += " AND pe.is_active=?"
        params.append(int(active))
    if dept: q+=" AND pe.department_id=?"; params.append(dept)
    if cat:  q+=" AND p.category=?";       params.append(cat)
    q += " ORDER BY pe.last_name, pe.first_name"
    with get_db() as c:
        rows = c.execute(q, params).fetchall()
    return jsonify([dict(r) for r in rows])

@app.route("/api/personnel", methods=["POST"])
@api_login_required
def api_add_personnel():
    d = request.json
    req=("employee_no","first_name","last_name","email","position_id","employment_status","date_hired")
    if not all(d.get(k) for k in req):
        return jsonify({"error":"Missing required fields"}), 400
    with get_db() as c:
        try:
            cur = c.execute("""
                INSERT INTO personnel
                  (employee_no,applicant_id,first_name,middle_name,last_name,suffix,
                   gender,date_of_birth,email,phone,address,position_id,department_id,
                   employment_status,date_hired,date_regularized,salary_grade,profile_notes)
                VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
                (d["employee_no"],d.get("applicant_id"),d["first_name"],d.get("middle_name"),
                 d["last_name"],d.get("suffix"),d.get("gender"),d.get("date_of_birth"),
                 d["email"],d.get("phone"),d.get("address"),d["position_id"],
                 d.get("department_id"),d["employment_status"],d["date_hired"],
                 d.get("date_regularized"),d.get("salary_grade"),d.get("profile_notes")))
        except sqlite3.IntegrityError as e:
            return jsonify({"error":str(e)}), 409
    return jsonify({"id":cur.lastrowid,"message":"Personnel record added"}), 201

@app.route("/api/personnel/<int:pid>", methods=["PUT"])
@api_login_required
def api_update_personnel(pid):
    d = request.json
    ALLOWED_FIELDS = {"first_name","middle_name","last_name","suffix","gender","date_of_birth",
                      "email","phone","address","position_id","department_id","employment_status",
                      "date_hired","date_regularized","salary_grade","profile_notes","is_active"}
    fields=["first_name","middle_name","last_name","suffix","gender","date_of_birth",
            "email","phone","address","position_id","department_id","employment_status",
            "date_hired","date_regularized","salary_grade","profile_notes","is_active"]
    sets=[f"{f}=?" for f in fields if f in d and f in ALLOWED_FIELDS]
    vals=[d[f]    for f in fields if f in d and f in ALLOWED_FIELDS]
    if not sets: return jsonify({"error":"Nothing to update"}), 400
    vals += [datetime.utcnow().isoformat(), pid]
    with get_db() as c:
        c.execute(f"UPDATE personnel SET {', '.join(sets)}, updated_at=? WHERE id=?", vals)
    return jsonify({"message":"Personnel updated"})

@app.route("/api/personnel/<int:pid>", methods=["DELETE"])
@api_login_required
def api_deactivate_personnel(pid):
    with get_db() as c:
        c.execute("UPDATE personnel SET is_active=0, updated_at=? WHERE id=?",
                  (datetime.utcnow().isoformat(), pid))
    return jsonify({"message":"Personnel deactivated"})

@app.route("/api/personnel/<int:pid>/reactivate", methods=["PUT"])
@api_login_required
def api_reactivate_personnel(pid):
    with get_db() as c:
        c.execute("UPDATE personnel SET is_active=1, updated_at=? WHERE id=?",
                  (datetime.utcnow().isoformat(), pid))
    return jsonify({"message":"Personnel reactivated"})

@app.route("/api/stats")
@api_login_required
def api_stats():
    with get_db() as c:
        total_apps  = c.execute("SELECT COUNT(*) FROM applications").fetchone()[0]
        total_staff = c.execute("SELECT COUNT(*) FROM personnel WHERE is_active=1").fetchone()[0]
        total_pos   = c.execute("SELECT COUNT(*) FROM positions WHERE is_active=1").fetchone()[0]
        hired       = c.execute("SELECT COUNT(*) FROM applications WHERE status='Hired'").fetchone()[0]
        by_status   = c.execute("SELECT status, COUNT(*) c FROM applications GROUP BY status").fetchall()
        by_dept     = c.execute("""
            SELECT d.name, d.code, COUNT(pe.id) c
            FROM departments d LEFT JOIN personnel pe ON pe.department_id=d.id AND pe.is_active=1
            GROUP BY d.id ORDER BY c DESC""").fetchall()
        by_category = c.execute("""
            SELECT p.category, COUNT(pe.id) c
            FROM positions p LEFT JOIN personnel pe ON pe.position_id=p.id AND pe.is_active=1
            GROUP BY p.category""").fetchall()
    return jsonify({
        "total_applications": total_apps,
        "total_personnel":    total_staff,
        "open_positions":     total_pos,
        "hired":              hired,
        "by_status":          [dict(r) for r in by_status],
        "by_department":      [dict(r) for r in by_dept],
        "by_category":        [dict(r) for r in by_category],
    })

