def _pdf_header(story, styles, subtitle):
    story.append(Paragraph("SAN JOSE LITEX SENIOR HIGH SCHOOL", styles['SchoolTitle']))
    story.append(Paragraph(subtitle, styles['ReportSub']))
    story.append(Paragraph(f"Generated: {datetime.now().strftime('%B %d, %Y  %I:%M %p')}", styles['ReportSub']))
    story.append(Spacer(1, 6))
    story.append(HRFlowable(width="100%", thickness=2, color=PDF_GOLD, spaceAfter=8))


def _pptx_title_slide(prs, title, subtitle):
    blank = prs.slide_layouts[6]
    slide = prs.slides.add_slide(blank)

    bg = slide.background.fill
    bg.solid()
    bg.fore_color.rgb = PPTX_NAVY

    # gold accent bar
    bar = slide.shapes.add_shape(1, Inches(0), Inches(3.05), Inches(0.18), Inches(1.3))
    bar.fill.solid(); bar.fill.fore_color.rgb = PPTX_GOLD
    bar.line.fill.background()

    # school name
    tb1 = slide.shapes.add_textbox(Inches(0.35), Inches(2.35), Inches(12.6), Inches(0.9))
    p1  = tb1.text_frame.paragraphs[0]
    r1  = p1.add_run()
    r1.text = "San Jose Litex Senior High School"
    r1.font.size  = Pt(34); r1.font.bold = True
    r1.font.color.rgb = PPTX_WHITE; r1.font.name = "Calibri"

    # subtitle
    tb2 = slide.shapes.add_textbox(Inches(0.35), Inches(3.35), Inches(12.6), Inches(0.75))
    p2  = tb2.text_frame.paragraphs[0]
    r2  = p2.add_run()
    r2.text = title
    r2.font.size  = Pt(22)
    r2.font.color.rgb = PPTX_GOLD; r2.font.name = "Calibri"

    # date
    tb3 = slide.shapes.add_textbox(Inches(0.35), Inches(4.2), Inches(12.6), Inches(0.5))
    p3  = tb3.text_frame.paragraphs[0]
    r3  = p3.add_run()
    r3.text = subtitle
    r3.font.size  = Pt(12)
    r3.font.color.rgb = PPTX_MUTED; r3.font.name = "Calibri"

def _pptx_slide_header(slide, title_text):
    bar = slide.shapes.add_shape(1, Inches(0), Inches(0), Inches(13.33), Inches(1.0))
    bar.fill.solid(); bar.fill.fore_color.rgb = PPTX_NAVY
    bar.line.fill.background()
    tb = slide.shapes.add_textbox(Inches(0.4), Inches(0.15), Inches(12), Inches(0.7))
    p  = tb.text_frame.paragraphs[0]
    r  = p.add_run()
    r.text = title_text
    r.font.size = Pt(20); r.font.bold = True
    r.font.color.rgb = PPTX_WHITE; r.font.name = "Calibri"

def _xl_header(ws, section, subtitle, col_span):
    """Write a styled header block at the top of an Excel worksheet."""
    navy_fill = PatternFill(start_color='0D1B3E', end_color='0D1B3E', fill_type='solid')
    gold_fill = PatternFill(start_color='F0A500', end_color='F0A500', fill_type='solid')
    # Row 1: school name
    ws.cell(1, 1, "SAN JOSE LITEX SENIOR HIGH SCHOOL").fill = navy_fill
    ws.cell(1, 1).font = Font(name='Arial', size=13, bold=True, color='FFFFFF')
    ws.cell(1, 1).alignment = Alignment(horizontal='center', vertical='center')
    ws.row_dimensions[1].height = 28
    # Row 2: report subtitle
    ws.cell(2, 1, subtitle).fill = gold_fill
    ws.cell(2, 1).font = Font(name='Arial', size=10, bold=True, color='0D1B3E')
    ws.cell(2, 1).alignment = Alignment(horizontal='center', vertical='center')
    ws.row_dimensions[2].height = 20
    # Row 3: generated date
    from datetime import datetime
    ws.cell(3, 1, f"Generated: {datetime.now().strftime('%B %d, %Y  %I:%M %p')}")
    ws.cell(3, 1).font = Font(name='Arial', size=9, italic=True, color='6B7BA4')
    ws.cell(3, 1).alignment = Alignment(horizontal='center')
    ws.row_dimensions[3].height = 16
    # Merge header rows across columns
    from openpyxl.utils import get_column_letter
    last_col = get_column_letter(col_span)
    for row in [1, 2, 3]:
        ws.merge_cells(f'A{row}:{last_col}{row}')

def _pptx_set_cell(cell, text, is_header=False, alt_row=False):
    cell.text = str(text)
    tf  = cell.text_frame
    tf.word_wrap = True
    p   = tf.paragraphs[0]
    run = p.runs[0] if p.runs else p.add_run()
    run.font.name = "Calibri"
    if is_header:
        run.font.size  = Pt(9); run.font.bold = True
        run.font.color.rgb = PPTX_WHITE
        cell.fill.solid(); cell.fill.fore_color.rgb = PPTX_NAVY
    else:
        run.font.size  = Pt(8)
        run.font.color.rgb = PPTX_NAVY
        cell.fill.solid()
        cell.fill.fore_color.rgb = PPTX_LIGHT if alt_row else RGBColor(0xff, 0xff, 0xff)

