#  EXPORT ROUTES — PERSONNEL
# ══════════════════════════════════════════════════════════════════

def _fetch_personnel_all():
    with get_db() as c:
        return c.execute("""
            SELECT pe.*, p.title position_title, p.category,
                   d.name dept_name, d.code dept_code
            FROM personnel pe
            JOIN positions p ON p.id = pe.position_id
            LEFT JOIN departments d ON d.id = pe.department_id
            ORDER BY pe.last_name, pe.first_name
        """).fetchall()

@app.route("/api/export/personnel/pdf")
@api_login_required
def export_personnel_pdf():
    rows = _fetch_personnel_all()
    buf  = io.BytesIO()
    doc  = SimpleDocTemplate(buf, pagesize=landscape(A4),
                              leftMargin=1.5*cm, rightMargin=1.5*cm,
                              topMargin=1.5*cm, bottomMargin=1.5*cm)
    styles = _pdf_styles()
    story  = []
    _pdf_header(story, styles, "School Personnel Report")

    headers = ['#', 'Emp. No.', 'Name', 'Position', 'Department',
               'Category', 'Emp. Status', 'Date Hired', 'Salary Grade', 'Active']
    data = [headers]
    for i, r in enumerate(rows, 1):
        name = f"{r['last_name']}, {r['first_name']}"
        if r['middle_name']: name += f" {r['middle_name'][0]}."
        data.append([
            str(i), r['employee_no'], name, r['position_title'],
            r['dept_name'] or '—', r['category'], r['employment_status'],
            r['date_hired'] or '—', r['salary_grade'] or '—',
            'Yes' if r['is_active'] else 'No'
        ])

    col_w = [.7*cm, 2*cm, 4*cm, 5*cm, 4.5*cm, 2.8*cm, 2.8*cm, 2.5*cm, 2.2*cm, 1.4*cm]
    t = Table(data, colWidths=col_w, repeatRows=1)
    t.setStyle(_pdf_table_style())
    story.append(t)

    # Summary footer
    story.append(Spacer(1, 10))
    active_n = sum(1 for r in rows if r['is_active'])
    story.append(Paragraph(
        f"<b>Total Records:</b> {len(rows)}  &nbsp;|&nbsp;  "
        f"<b>Active:</b> {active_n}  &nbsp;|&nbsp;  "
        f"<b>Inactive:</b> {len(rows) - active_n}",
        styles['ReportSub']))

    doc.build(story)
    buf.seek(0)
    return send_file(buf, mimetype='application/pdf', as_attachment=True,
                     download_name=f'SJL_Personnel_{datetime.now().strftime("%Y%m%d")}.pdf')



@app.route("/api/export/personnel/pptx")
@api_login_required
def export_personnel_pptx():
    rows  = _fetch_personnel_all()
    prs   = Presentation()
    prs.slide_width  = Inches(13.33)
    prs.slide_height = Inches(7.5)
    blank = prs.slide_layouts[6]

    today_str = datetime.now().strftime('%B %d, %Y')

    # Slide 1 — Title
    _pptx_title_slide(prs, "School Personnel Report",
                      f"Generated: {today_str}  |  Total Records: {len(rows)}")

    # Slide 2 — Summary stats
    active_rows  = [r for r in rows if r['is_active']]
    cat_counts   = Counter(r['category']           for r in active_rows)
    dept_counts  = Counter(r['dept_name'] or '—'   for r in active_rows)

    slide2 = prs.slides.add_slide(blank)
    bg2 = slide2.background.fill; bg2.solid(); bg2.fore_color.rgb = PPTX_LIGHT
    _pptx_slide_header(slide2, "Personnel Overview")

    stats = [
        (str(len(active_rows)),                "Active Personnel"),
        (str(len(rows)),                       "Total Records"),
        (str(cat_counts.get('Teaching', 0)),   "Teaching Staff"),
        (str(cat_counts.get('Non-Teaching',0)
            + cat_counts.get('Administrative',0)
            + cat_counts.get('Support',0)),    "Other Staff"),
    ]
    for i, (num, lbl) in enumerate(stats):
        x = Inches(0.3 + i * 3.2); y = Inches(1.5)
        card = slide2.shapes.add_shape(1, x, y, Inches(2.95), Inches(1.9))
        card.fill.solid(); card.fill.fore_color.rgb = RGBColor(0xff,0xff,0xff)
        card.line.color.rgb = RGBColor(0xd8,0xdf,0xf0)
        stripe = slide2.shapes.add_shape(1, x, y, Inches(2.95), Inches(0.1))
        stripe.fill.solid(); stripe.fill.fore_color.rgb = PPTX_CARD_COLORS[i]
        stripe.line.fill.background()
        nt = slide2.shapes.add_textbox(x+Inches(.15), y+Inches(.25), Inches(2.65), Inches(.9))
        nr = nt.text_frame.paragraphs[0].add_run()
        nr.text = num; nr.font.size = Pt(40); nr.font.bold = True
        nr.font.color.rgb = PPTX_NAVY; nr.font.name = "Calibri"
        lt = slide2.shapes.add_textbox(x+Inches(.15), y+Inches(1.2), Inches(2.65), Inches(.55))
        lr = lt.text_frame.paragraphs[0].add_run()
        lr.text = lbl; lr.font.size = Pt(11)
        lr.font.color.rgb = PPTX_MUTED; lr.font.name = "Calibri"

    # Category bar chart visual
    max_c = max(cat_counts.values(), default=1)
    for i, (cat, cnt) in enumerate(cat_counts.most_common()):
        ry = Inches(3.75 + i * 0.52)
        lt = slide2.shapes.add_textbox(Inches(0.4), ry, Inches(2.5), Inches(0.4))
        lr = lt.text_frame.paragraphs[0].add_run()
        lr.text = cat; lr.font.size = Pt(10); lr.font.color.rgb = PPTX_NAVY
        lr.font.name = "Calibri"
        bg_bar = slide2.shapes.add_shape(1, Inches(3.1), ry+Inches(.08), Inches(8), Inches(.25))
        bg_bar.fill.solid(); bg_bar.fill.fore_color.rgb = RGBColor(0xe5,0xe7,0xeb)
        bg_bar.line.fill.background()
        fw = 8.0 * cnt / max_c
        fg_bar = slide2.shapes.add_shape(1, Inches(3.1), ry+Inches(.08), Inches(fw), Inches(.25))
        fg_bar.fill.solid(); fg_bar.fill.fore_color.rgb = PPTX_CARD_COLORS[i % 4]
        fg_bar.line.fill.background()
        ct = slide2.shapes.add_textbox(Inches(11.3), ry, Inches(.7), Inches(.4))
        cr = ct.text_frame.paragraphs[0].add_run()
        cr.text = str(cnt); cr.font.size = Pt(10); cr.font.bold = True
        cr.font.color.rgb = PPTX_NAVY; cr.font.name = "Calibri"

    # Slides 3+ — Personnel tables (15 rows per slide)
    ROWS_PER = 15
    for si in range(0, len(active_rows), ROWS_PER):
        chunk   = active_rows[si:si + ROWS_PER]
        slide_n = prs.slides.add_slide(blank)
        bg_n    = slide_n.background.fill; bg_n.solid(); bg_n.fore_color.rgb = RGBColor(0xff,0xff,0xff)
        end_rec = min(si + ROWS_PER, len(active_rows))
        _pptx_slide_header(slide_n,
            f"Active Personnel — Records {si+1}–{end_rec}  "
            f"(Page {si//ROWS_PER + 1}/{-(-len(active_rows)//ROWS_PER)})")

        pg_tb = slide_n.shapes.add_textbox(Inches(11.5), Inches(.18), Inches(1.7), Inches(.6))
        pg_p  = pg_tb.text_frame.paragraphs[0]; pg_p.alignment = PP_ALIGN.RIGHT
        pg_r  = pg_p.add_run(); pg_r.text = f"SJL-SHS"
        pg_r.font.size = Pt(10); pg_r.font.color.rgb = PPTX_GOLD; pg_r.font.name = "Calibri"

        tbl_data = [['Emp. No.', 'Full Name', 'Position', 'Department',
                     'Category', 'Emp. Status', 'Date Hired']]
        for r in chunk:
            name = f"{r['last_name']}, {r['first_name']}"
            if r['middle_name']: name += f" {r['middle_name'][0]}."
            tbl_data.append([r['employee_no'], name, r['position_title'],
                             (r['dept_name'] or '—'), r['category'],
                             r['employment_status'], r['date_hired'] or '—'])

        tr_cnt = len(tbl_data)
        tbl = slide_n.shapes.add_table(
            tr_cnt, 7, Inches(0.2), Inches(1.1), Inches(12.9), Inches(6.1)).table

        for ci, cw in enumerate([1.3, 2.6, 3.2, 2.4, 1.6, 1.6, 1.2]):
            tbl.columns[ci].width = Inches(cw)

        for ri, row in enumerate(tbl_data):
            for ci, val in enumerate(row):
                _pptx_set_cell(tbl.cell(ri, ci), val,
                               is_header=(ri == 0),
                               alt_row=(ri % 2 == 0 and ri > 0))

    buf = io.BytesIO()
    prs.save(buf); buf.seek(0)
    return send_file(buf,
                     mimetype='application/vnd.openxmlformats-officedocument.presentationml.presentation',
                     as_attachment=True,
                     download_name=f'SJL_Personnel_{datetime.now().strftime("%Y%m%d")}.pptx')

