#  EXPORT ROUTES — DASHBOARD
# ══════════════════════════════════════════════════════════════════

def _fetch_dashboard_data():
    with get_db() as c:
        total_apps  = c.execute("SELECT COUNT(*) FROM applications").fetchone()[0]
        total_staff = c.execute("SELECT COUNT(*) FROM personnel WHERE is_active=1").fetchone()[0]
        total_pos   = c.execute("SELECT COUNT(*) FROM positions WHERE is_active=1").fetchone()[0]
        hired       = c.execute("SELECT COUNT(*) FROM applications WHERE status='Hired'").fetchone()[0]
        by_dept     = c.execute("""
            SELECT d.name, d.code, COUNT(pe.id) c
            FROM departments d LEFT JOIN personnel pe
              ON pe.department_id=d.id AND pe.is_active=1
            GROUP BY d.id ORDER BY c DESC""").fetchall()
        by_category = c.execute("""
            SELECT p.category, COUNT(pe.id) c
            FROM positions p LEFT JOIN personnel pe
              ON pe.position_id=p.id AND pe.is_active=1
            GROUP BY p.category ORDER BY c DESC""").fetchall()
    return {
        "total_apps": total_apps, "total_staff": total_staff,
        "total_pos": total_pos,   "hired": hired,
        "by_dept": by_dept,       "by_category": by_category,
    }


@app.route("/api/export/dashboard/pdf")
@api_login_required
def export_dashboard_pdf():
    d      = _fetch_dashboard_data()
    buf    = io.BytesIO()
    doc    = SimpleDocTemplate(buf, pagesize=A4,
                                leftMargin=1.8*cm, rightMargin=1.8*cm,
                                topMargin=1.5*cm, bottomMargin=1.5*cm)
    styles = _pdf_styles()
    story  = []
    _pdf_header(story, styles, "Dashboard Summary Report")

    # KPI cards as a table
    kpi_data = [
        ['Active Personnel', 'Open Positions'],
        [str(d['total_staff']), str(d['total_pos'])],
    ]
    kpi_style = TableStyle([
        ('BACKGROUND',   (0,0), (-1,0),  PDF_NAVY),
        ('TEXTCOLOR',    (0,0), (-1,0),  colors.white),
        ('FONTNAME',     (0,0), (-1,0),  'Helvetica-Bold'),
        ('FONTSIZE',     (0,0), (-1,0),  9),
        ('ALIGN',        (0,0), (-1,-1), 'CENTER'),
        ('BACKGROUND',   (0,1), (0,1),   PDF_LIGHT),
        ('BACKGROUND',   (1,1), (1,1),   colors.HexColor('#fef2f2')),
        ('FONTNAME',     (0,1), (-1,1),  'Helvetica-Bold'),
        ('FONTSIZE',     (0,1), (-1,1),  24),
        ('TEXTCOLOR',    (0,1), (-1,1),  PDF_NAVY),
        ('GRID',         (0,0), (-1,-1), 0.5, colors.HexColor('#d8dff0')),
        ('TOPPADDING',   (0,0), (-1,-1), 8),
        ('BOTTOMPADDING',(0,0), (-1,-1), 8),
    ])
    kw = (doc.width / 2)
    kpi_t = Table(kpi_data, colWidths=[kw]*2)
    kpi_t.setStyle(kpi_style)
    story.append(kpi_t)
    story.append(Spacer(1, 14))

    # Dept table
    story.append(Paragraph("Personnel by Department", styles['SectionHead']))
    dept_headers = ['Department', 'Code', 'Active Personnel']
    dept_data    = [dept_headers] + [[r['name'], r['code'], str(r['c'])] for r in d['by_dept']]
    dept_w       = [10*cm, 3*cm, 4*cm]
    dt = Table(dept_data, colWidths=dept_w)
    dt.setStyle(_pdf_table_style())
    story.append(dt)
    story.append(Spacer(1, 14))

    # Category table
    story.append(Paragraph("Personnel by Category", styles['SectionHead']))
    cat_data = [['Category', 'Active Personnel']] + [[r['category'], str(r['c'])] for r in d['by_category']]
    cat_w    = [10*cm, 7*cm]
    ct2 = Table(cat_data, colWidths=cat_w)
    ct2.setStyle(_pdf_table_style())
    story.append(ct2)

    doc.build(story)
    buf.seek(0)
    return send_file(buf, mimetype='application/pdf', as_attachment=True,
                     download_name=f'SJL_Dashboard_{datetime.now().strftime("%Y%m%d")}.pdf')


@app.route("/api/export/dashboard/excel")
@api_login_required
def export_dashboard_excel():
    d  = _fetch_dashboard_data()
    wb = openpyxl.Workbook()

    # ── Sheet 1: Summary ─────────────────────────────────────────
    ws = wb.active
    ws.title = "Dashboard Summary"
    _xl_header(ws, "Dashboard", "Dashboard Summary Report", 2)

    kpi_labels = ['Active Personnel', 'Open Positions']
    kpi_values = [d['total_staff'], d['total_pos']]
    navy_fill  = PatternFill(start_color='0D1B3E', end_color='0D1B3E', fill_type='solid')
    light_fill = PatternFill(start_color='F0F3FB', end_color='F0F3FB', fill_type='solid')

    for ci, lbl in enumerate(kpi_labels, 1):
        cell = ws.cell(5, ci, lbl)
        cell.fill = navy_fill
        cell.font = Font(name='Arial', size=10, bold=True, color='FFFFFF')
        cell.alignment = Alignment(horizontal='center', vertical='center')
    ws.row_dimensions[5].height = 24

    for ci, val in enumerate(kpi_values, 1):
        cell = ws.cell(6, ci, val)
        cell.fill = light_fill
        cell.font = Font(name='Arial', size=20, bold=True, color='0D1B3E')
        cell.alignment = Alignment(horizontal='center', vertical='center')
    ws.row_dimensions[6].height = 36

    # Dept section
    ws['A8'].value = "Department";         ws['B8'].value = "Code"
    ws['C8'].value = "Active Personnel"
    for col in 'ABC':
        ws[f'{col}8'].fill = navy_fill
        ws[f'{col}8'].font = Font(name='Arial', size=9, bold=True, color='FFFFFF')
        ws[f'{col}8'].alignment = Alignment(horizontal='center')
    ws.row_dimensions[8].height = 22
    for i, r in enumerate(d['by_dept'], 9):
        fill = light_fill if i % 2 == 0 else PatternFill(fill_type='none')
        for ci, val in enumerate([r['name'], r['code'], r['c']], 1):
            cell = ws.cell(i, ci, val)
            cell.fill = fill
            cell.font = Font(name='Arial', size=9)
            cell.alignment = Alignment(horizontal='left' if ci < 3 else 'center')

    # Category section
    start_cat = len(d['by_dept']) + 10
    c1 = ws.cell(start_cat, 1, "Category")
    c1.fill = navy_fill
    ws.cell(start_cat, 1).font = Font(name='Arial', size=9, bold=True, color='FFFFFF')
    ws.cell(start_cat, 1).alignment = Alignment(horizontal='center')
    c2 = ws.cell(start_cat, 2, "Active Personnel")
    c2.fill = navy_fill
    ws.cell(start_cat, 2).font = Font(name='Arial', size=9, bold=True, color='FFFFFF')
    ws.cell(start_cat, 2).alignment = Alignment(horizontal='center')
    ws.row_dimensions[start_cat].height = 22
    for i, r in enumerate(d['by_category'], start_cat + 1):
        ws.cell(i, 1, r['category']).font = Font(name='Arial', size=9)
        ws.cell(i, 2, r['c']).font        = Font(name='Arial', size=9)
        ws.cell(i, 2).alignment           = Alignment(horizontal='center')

    for col, w in zip('ABCD', [36, 10, 20, 20]):
        ws.column_dimensions[col].width = w

    buf = io.BytesIO()
    wb.save(buf); buf.seek(0)
    return send_file(buf,
                     mimetype='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
                     as_attachment=True,
                     download_name=f'SJL_Dashboard_{datetime.now().strftime("%Y%m%d")}.xlsx')


